createPreferences(input: CreateUserPreferencesInput): UserPreferences {
  const existing = this.preferencesRepo.findByUserId(input.userId);
  if (existing) {
    throw new Error(`Preferences already exist for user: ${input.userId}`);
  }

  const now = new Date();
  const emailSettings = {
    ...DEFAULT_EMAIL_SETTINGS,
    ...input.email,
    subscribedCategories: input.email?.subscribedCategories
      ? [...input.email.subscribedCategories]
      : [...DEFAULT_EMAIL_SETTINGS.subscribedCategories],
  };

  const smsSettings = {
    ...DEFAULT_SMS_SETTINGS,
    ...input.sms,
    subscribedCategories: input.sms?.subscribedCategories
      ? [...input.sms.subscribedCategories]
      : [...DEFAULT_SMS_SETTINGS.subscribedCategories],
  };

  const webhookSettings = {
    ...DEFAULT_WEBHOOK_SETTINGS,
    ...input.webhook,
    subscribedCategories: input.webhook?.subscribedCategories
      ? [...input.webhook.subscribedCategories]
      : [...DEFAULT_WEBHOOK_SETTINGS.subscribedCategories],
  };

  const preferences: UserPreferences = {
    id: generatePreferencesId(),
    userId: input.userId,
    email: emailSettings,
    sms: smsSettings,
    webhook: webhookSettings,
    createdAt: now,
    updatedAt: now,
  };

  this.preferencesRepo.save(preferences);
  this.logger.info(`Created preferences for user: ${input.userId}`);
