/**
 * Check whether a user should receive a specific email notification.
 * Returns true if:
 * - No preferences exist (default: send all notifications)
 * - Email is enabled AND the notification type is in subscribedCategories
 */
shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.preferencesRepo.findByUserId(userId);

  // No preferences means the user hasn't opted out — send everything
  if (!prefs) {
    return true;
  }

  if (!prefs.email.enabled) {
    return false;
  }

  return prefs.email.subscribedCategories.includes(notificationType);
}

/**
 * Check whether a user should receive a specific SMS notification.
 * Returns true if:
 * - No preferences exist (default: SMS is disabled, so returns false)
 * - SMS is enabled AND the notification type is in subscribedCategories
 */
shouldSendSms(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.preferencesRepo.findByUserId(userId);

  // No preferences — SMS defaults to disabled (opt-in channel)
  if (!prefs) {
    return false;
  }

  if (!prefs.sms.enabled) {
    return false;
  }

  return prefs.sms.subscribedCategories.includes(notificationType);
}

